"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const columns=['Context','Evidence','Decision'];
export default function ReadingPulseColumns(){const [active,setActive]=useState(0);const reduced=useReducedMotion();return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-4 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><div className="h-1 rounded-full bg-[#ececee]"><motion.i animate={{x:active*94}} transition={reduced?{duration:.12}:{type:"spring",stiffness:290,damping:26}} className="block h-1 w-8 rounded-full bg-[#84cc16]"/></div><div tabIndex={0} aria-label="Scrollable reading columns" onScroll={e=>setActive(Math.min(2,Math.round(e.currentTarget.scrollTop/118)))} className="mt-3 h-56 overflow-y-auto rounded-[18px] bg-[#f4f5f6] p-3 outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{columns.map((column,i)=><motion.article key={column} initial={reduced?false:{opacity:0,y:8}} whileInView={{opacity:1,y:0}} transition={{duration:.18}} className="mb-3 min-h-28 rounded-[18px] border border-[#ececee] bg-white p-4"><p className="text-xs font-bold text-[#4a4a4f]">0{i+1} {active===i?'CURRENT':''}</p><h2 className="mt-2 text-lg font-black text-[#111]">{column}</h2><p className="mt-2 text-xs text-[#4a4a4f]">A short reading checkpoint with space to continue.</p></motion.article>)}</div><p aria-live="polite" className="mt-2 text-xs text-[#4a4a4f]">Current column: {columns[active]}.</p></section>}
